use std::arch::x86_64::*;

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());

    unsafe {
        l2_distance_avx512(a, b)
    }
}

#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let len = a.len();
    let mut sum0 = _mm512_setzero_ps();
    let mut sum1 = _mm512_setzero_ps();

    // Process 32 elements at a time (2 AVX-512 registers)
    let mut i = 0;
    while i + 32 <= len {
        let va0 = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb0 = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(diff0, diff0, sum0);

        let va1 = _mm512_loadu_ps(a.as_ptr().add(i + 16));
        let vb1 = _mm512_loadu_ps(b.as_ptr().add(i + 16));
        let diff1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(diff1, diff1, sum1);

        i += 32;
    }

    // Process remaining 16 elements
    if i + 16 <= len {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        sum0 = _mm512_fmadd_ps(diff, diff, sum0);
        i += 16;
    }

    // Sum the accumulators
    sum0 = _mm512_add_ps(sum0, sum1);
    let mut result = _mm512_reduce_add_ps(sum0) as f64;

    // Handle remaining elements
    while i < len {
        let diff = *a.get_unchecked(i) - *b.get_unchecked(i);
        result += (diff * diff) as f64;
        i += 1;
    }

    result
}

use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

#[derive(Clone, Copy)]
struct SearchCandidate {
    id: u64,
    distance: f64,
}

impl PartialEq for SearchCandidate {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for SearchCandidate {}

impl PartialOrd for SearchCandidate {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for SearchCandidate {
    fn cmp(&self, other: &Self) -> Ordering {
        // Reverse ordering for min-heap (we want smallest distances)
        other.distance.partial_cmp(&self.distance).unwrap_or(Ordering::Equal)
    }
}

pub struct VectorDB {
    vectors: RwLock<Vec<(u64, Vec<f32>)>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut vecs = self.vectors.write().unwrap();
        vecs.push((id, vector));
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut vecs = self.vectors.write().unwrap();
        let count = vectors.len();
        vecs.extend(vectors);
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let vecs = self.vectors.read().unwrap();

        if vecs.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;

        // Parallel search using rayon
        let results: Vec<SearchCandidate> = vecs
            .par_iter()
            .map(|(id, vec)| {
                SearchCandidate {
                    id: *id,
                    distance: l2_distance(query, vec),
                }
            })
            .collect();

        // Use a max-heap to find top-k
        let mut heap = BinaryHeap::with_capacity(top_k);

        for candidate in results {
            if heap.len() < top_k {
                heap.push(candidate);
            } else if let Some(&max) = heap.peek() {
                if candidate.distance < max.distance {
                    heap.pop();
                    heap.push(candidate);
                }
            }
        }

        // Convert to sorted result (ascending by distance)
        let mut results: Vec<SearchCandidate> = heap.into_sorted_vec();
        results.reverse();

        results
            .into_iter()
            .map(|c| SearchResult {
                id: c.id,
                distance: c.distance,
            })
            .collect()
    }
}

