use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

const DIM: usize = 128;

#[derive(Clone, Copy)]
struct SearchCandidate {
    id: u64,
    distance: f64,
}

impl PartialEq for SearchCandidate {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for SearchCandidate {}

impl PartialOrd for SearchCandidate {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Max-heap based on distance - largest distance at top
impl Ord for SearchCandidate {
    fn cmp(&self, other: &Self) -> Ordering {
        self.distance.partial_cmp(&other.distance).unwrap_or(Ordering::Equal)
    }
}

pub struct VectorDB {
    // Flat storage: ids and vectors stored separately for better cache locality
    ids: RwLock<Vec<u64>>,
    data: RwLock<Vec<f32>>, // Flattened: [vec0[0..128], vec1[0..128], ...]
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        ids.push(id);
        data.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        let count = vectors.len();

        ids.reserve(count);
        data.reserve(count * DIM);

        for (id, vec) in vectors {
            ids.push(id);
            data.extend_from_slice(&vec);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let data = self.data.read().unwrap();

        if ids.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let num_vectors = ids.len();

        // Thread-local search with local heaps
        let global_results: Vec<SearchCandidate> = (0..num_vectors)
            .into_par_iter()
            .fold(
                || Vec::new(),
                |mut local_vec, idx| {
                    let start = idx * DIM;
                    let vec = &data[start..start + DIM];
                    let dist = l2_distance(query, vec);
                    local_vec.push(SearchCandidate {
                        id: ids[idx],
                        distance: dist,
                    });
                    local_vec
                }
            )
            .reduce(
                || Vec::new(),
                |mut a, mut b| {
                    a.append(&mut b);
                    a
                }
            );

        // Use a max-heap to find top-k
        let mut heap = BinaryHeap::with_capacity(top_k);

        for candidate in global_results {
            if heap.len() < top_k {
                heap.push(candidate);
            } else if let Some(&max) = heap.peek() {
                if candidate.distance < max.distance {
                    heap.pop();
                    heap.push(candidate);
                }
            }
        }

        // Convert to sorted result (ascending by distance)
        let mut results: Vec<SearchCandidate> = heap.into_sorted_vec();
        results.reverse(); // Now ascending order

        results
            .into_iter()
            .map(|c| SearchResult {
                id: c.id,
                distance: c.distance,
            })
            .collect()
    }
}

