pub struct VectorDB {
    // Flat storage: ids and vectors stored separately for better cache locality
    ids: RwLock<Vec<u64>>,
    data: RwLock<Vec<f32>>, // Flattened: [vec0[0..128], vec1[0..128], ...]
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        ids.push(id);
        data.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        let count = vectors.len();

        ids.reserve(count);
        data.reserve(count * DIM);

        for (id, vec) in vectors {
            ids.push(id);
            data.extend_from_slice(&vec);
        }
        count
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let data = self.data.read().unwrap();

        if ids.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let num_vectors = ids.len();

        // Each thread maintains its own heap
        let thread_heaps: Vec<BinaryHeap<SearchCandidate>> = (0..num_vectors)
            .into_par_iter()
            .fold(
                || BinaryHeap::with_capacity(top_k),
                |mut local_heap, idx| {
                    let start = idx * DIM;
                    let vec = &data[start..start + DIM];
                    let dist = l2_distance(query, vec);
                    let candidate = SearchCandidate {
                        id: ids[idx],
                        distance: dist,
                    };

                    if local_heap.len() < top_k {
                        local_heap.push(candidate);
                    } else if let Some(&max) = local_heap.peek() {
                        if candidate.distance < max.distance {
                            local_heap.pop();
                            local_heap.push(candidate);
                        }
                    }
                    local_heap
                }
            )
            .collect();

        // Merge all thread heaps
        let mut final_heap = BinaryHeap::with_capacity(top_k);
        for thread_heap in thread_heaps {
            for candidate in thread_heap {
                if final_heap.len() < top_k {
                    final_heap.push(candidate);
                } else if let Some(&max) = final_heap.peek() {
                    if candidate.distance < max.distance {
                        final_heap.pop();
                        final_heap.push(candidate);
                    }
                }
            }
        }

        // Convert to sorted result (ascending by distance)
        let mut results: Vec<SearchCandidate> = final_heap.into_sorted_vec();
        results.reverse(); // Now ascending order

        results
            .into_iter()
            .map(|c| SearchResult {
                id: c.id,
                distance: c.distance,
            })
            .collect()
    }
}

use std::arch::x86_64::*;

#[inline]
pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    debug_assert_eq!(a.len(), b.len());

    unsafe {
        l2_distance_avx512_unrolled(a, b)
    }
}

#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512_unrolled(a: &[f32], b: &[f32]) -> f64 {
    let len = a.len();
    let mut sum0 = _mm512_setzero_ps();
    let mut sum1 = _mm512_setzero_ps();
    let mut sum2 = _mm512_setzero_ps();
    let mut sum3 = _mm512_setzero_ps();

    // Process 64 elements at a time (4 AVX-512 registers)
    let mut i = 0;
    let aligned_len = len & !63; // Round down to multiple of 64

    while i < aligned_len {
        // 0-15
        let va0 = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb0 = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(diff0, diff0, sum0);

        // 16-31
        let va1 = _mm512_loadu_ps(a.as_ptr().add(i + 16));
        let vb1 = _mm512_loadu_ps(b.as_ptr().add(i + 16));
        let diff1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(diff1, diff1, sum1);

        // 32-47
        let va2 = _mm512_loadu_ps(a.as_ptr().add(i + 32));
        let vb2 = _mm512_loadu_ps(b.as_ptr().add(i + 32));
        let diff2 = _mm512_sub_ps(va2, vb2);
        sum2 = _mm512_fmadd_ps(diff2, diff2, sum2);

        // 48-63
        let va3 = _mm512_loadu_ps(a.as_ptr().add(i + 48));
        let vb3 = _mm512_loadu_ps(b.as_ptr().add(i + 48));
        let diff3 = _mm512_sub_ps(va3, vb3);
        sum3 = _mm512_fmadd_ps(diff3, diff3, sum3);

        i += 64;
    }

    // Handle remaining 32 elements
    if i + 32 <= len {
        let va0 = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb0 = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff0 = _mm512_sub_ps(va0, vb0);
        sum0 = _mm512_fmadd_ps(diff0, diff0, sum0);

        let va1 = _mm512_loadu_ps(a.as_ptr().add(i + 16));
        let vb1 = _mm512_loadu_ps(b.as_ptr().add(i + 16));
        let diff1 = _mm512_sub_ps(va1, vb1);
        sum1 = _mm512_fmadd_ps(diff1, diff1, sum1);

        i += 32;
    }

    // Handle remaining 16 elements
    if i + 16 <= len {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        sum0 = _mm512_fmadd_ps(diff, diff, sum0);
        i += 16;
    }

    // Sum all accumulators
    sum0 = _mm512_add_ps(sum0, sum1);
    sum2 = _mm512_add_ps(sum2, sum3);
    sum0 = _mm512_add_ps(sum0, sum2);

    let mut result = _mm512_reduce_add_ps(sum0) as f64;

    // Handle remaining elements
    while i < len {
        let diff = *a.get_unchecked(i) - *b.get_unchecked(i);
        result += (diff * diff) as f64;
        i += 1;
    }

    result
}

