    fn cmp(&self, other: &Self) -> Ordering {
        self.distance.partial_cmp(&other.distance).unwrap_or(Ordering::Equal)
    }
}

pub struct VectorDB {
    // Flat storage: ids and vectors stored separately for better cache locality
    ids: RwLock<Vec<u64>>,
    data: RwLock<Vec<f32>>, // Flattened: [vec0[0..128], vec1[0..128], ...]
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            data: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        ids.push(id);
        data.extend_from_slice(&vector);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut ids = self.ids.write().unwrap();
        let mut data = self.data.write().unwrap();
        let count = vectors.len();

        ids.reserve(count);
        data.reserve(count * DIM);

        for (id, vec) in vectors {
            ids.push(id);
            data.extend_from_slice(&vec);
        }
        count
    }

    fn search_chunk(
        ids: &[u64],
        data: &[f32],
        query: &[f32],
        top_k: usize,
    ) -> BinaryHeap<SearchCandidate> {
        let num_vectors = ids.len();
        let mut heap = BinaryHeap::with_capacity(top_k);

        for idx in 0..num_vectors {
            let start = idx * DIM;
            let vec = &data[start..start + DIM];
            let dist = l2_distance(query, vec);
            let candidate = SearchCandidate {
                id: ids[idx],
                distance: dist,
            };

            if heap.len() < top_k {
                heap.push(candidate);
            } else if let Some(&max) = heap.peek() {
                if candidate.distance < max.distance {
                    heap.pop();
                    heap.push(candidate);
                }
            }
        }

        heap
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read().unwrap();
        let data = self.data.read().unwrap();

        if ids.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let num_vectors = ids.len();

        // Determine number of chunks based on data size
        // Aim for at least 1000 vectors per chunk for efficiency
        let num_chunks = (num_vectors / 10000).clamp(4, 64);
        let chunk_size = (num_vectors + num_chunks - 1) / num_chunks;

        // Search chunks in parallel
        let chunk_heaps: Vec<BinaryHeap<SearchCandidate>> = (0..num_chunks)
            .into_par_iter()
            .map(|chunk_idx| {
                let start_idx = chunk_idx * chunk_size;
                let end_idx = ((chunk_idx + 1) * chunk_size).min(num_vectors);

                if start_idx >= num_vectors {
                    return BinaryHeap::new();
                }

                let chunk_ids = &ids[start_idx..end_idx];
                let chunk_data_start = start_idx * DIM;
                let chunk_data_end = end_idx * DIM;
                let chunk_data = &data[chunk_data_start..chunk_data_end];

                Self::search_chunk(chunk_ids, chunk_data, query, top_k)
            })
            .collect();

        // Merge chunk heaps
        let mut final_heap = BinaryHeap::with_capacity(top_k);
        for thread_heap in chunk_heaps {
            for candidate in thread_heap {
                if final_heap.len() < top_k {
                    final_heap.push(candidate);
                } else if let Some(&max) = final_heap.peek() {
                    if candidate.distance < max.distance {
                        final_heap.pop();
                        final_heap.push(candidate);
                    }
                }
            }
        }

        // Convert to sorted result (ascending by distance)
        let mut results: Vec<SearchCandidate> = final_heap.into_sorted_vec();
        results.reverse(); // Now ascending order

        results
            .into_iter()
            .map(|c| SearchResult {
                id: c.id,
                distance: c.distance,
            })
            .collect()
    }
}

