            a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal)
        });

        // Take first top_k and sort them
        let mut results: Vec<SearchCandidate> = all_candidates.into_iter().take(top_k).collect();
        results.sort_by(|a, b| {
            a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal)
        });

        results
            .into_iter()
            .map(|c| SearchResult {
                id: c.id,
                distance: c.distance,
            })
            .collect()
    }
}

use crate::api::*;
use crate::distance::l2_distance;
use std::sync::RwLock;
use rayon::prelude::*;
use std::collections::{BinaryHeap, HashSet};
use std::cmp::Ordering;
use rand::prelude::*;

const DIM: usize = 128;
const M: usize = 16; // Number of neighbors per node
const EF_CONSTRUCTION: usize = 100;
const EF_SEARCH: usize = 64;

#[derive(Clone, Copy, Debug)]
struct SearchCandidate {
    id: u64,
    distance: f64,
}

impl PartialEq for SearchCandidate {
    fn eq(&self, other: &Self) -> bool {
        self.distance == other.distance
    }
}

impl Eq for SearchCandidate {}

impl PartialOrd for SearchCandidate {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

// Min-heap for candidates (closest first)
impl Ord for SearchCandidate {
    fn cmp(&self, other: &Self) -> Ordering {
        other.distance.partial_cmp(&self.distance).unwrap_or(Ordering::Equal)
    }
}

struct Node {
    id: u64,
    vector: Vec<f32>,
    neighbors: Vec<usize>, // indices into the nodes array
}

pub struct VectorDB {
    nodes: RwLock<Vec<Node>>,
    id_to_idx: RwLock<std::collections::HashMap<u64, usize>>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            nodes: RwLock::new(Vec::new()),
            id_to_idx: RwLock::new(std::collections::HashMap::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut nodes = self.nodes.write().unwrap();
        let mut id_to_idx = self.id_to_idx.write().unwrap();

        let idx = nodes.len();
        nodes.push(Node {
            id,
            vector,
            neighbors: Vec::new(),
        });
        id_to_idx.insert(id, idx);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut nodes = self.nodes.write().unwrap();
        let mut id_to_idx = self.id_to_idx.write().unwrap();

        let start_idx = nodes.len();
        let count = vectors.len();

        // Add all nodes
        for (i, (id, vector)) in vectors.into_iter().enumerate() {
            let idx = start_idx + i;
            id_to_idx.insert(id, idx);
            nodes.push(Node {
                id,
                vector,
                neighbors: Vec::with_capacity(M),
            });
        }

        // Build NSW graph - connect each node to its M nearest neighbors among previous nodes
        // This creates a navigable small world structure
        for i in start_idx..nodes.len() {
            let query = nodes[i].vector.clone();
            let mut neighbors = Vec::with_capacity(M);

            if i > 0 {
                // Find M nearest neighbors among existing nodes
                let mut heap = BinaryHeap::with_capacity(M);
                for j in 0..i {
                    let dist = l2_distance(&query, &nodes[j].vector);
                    if heap.len() < M {
                        heap.push(SearchCandidate { id: j as u64, distance: dist });
                    } else if let Some(&max) = heap.peek() {
                        if dist < max.distance {
                            heap.pop();
                            heap.push(SearchCandidate { id: j as u64, distance: dist });
                        }
                    }
                }

                for cand in heap {
                    neighbors.push(cand.id as usize);
                    // Add reverse edge (undirected graph)
                    if nodes[cand.id as usize].neighbors.len() < M * 2 {
                        nodes[cand.id as usize].neighbors.push(i);
                    }
                }
            }

            nodes[i].neighbors = neighbors;
        }

        count
    }

    fn search_nsw(&self, query: &[f32], ef: usize, nodes: &Vec<Node>) -> Vec<SearchCandidate> {
        if nodes.is_empty() {
            return Vec::new();
        }

        // Random entry point
        let mut rng = thread_rng();
        let entry_point = rng.gen_range(0..nodes.len());

        let mut visited: HashSet<usize> = HashSet::new();
        let mut candidates: BinaryHeap<SearchCandidate> = BinaryHeap::new(); // min-heap (closest first)
        let mut results: BinaryHeap<SearchCandidate> = BinaryHeap::new(); // max-heap for top-k

        // Distance to entry point
        let dist = l2_distance(query, &nodes[entry_point].vector);
        candidates.push(SearchCandidate { id: entry_point as u64, distance: dist });
        results.push(SearchCandidate { id: entry_point as u64, distance: -dist }); // Negate for max-heap
        visited.insert(entry_point);

        while let Some(current) = candidates.pop() {
            // Check if we should stop (worst result is better than current)
            if let Some(&worst) = results.peek() {
                if current.distance > -worst.distance {
                    break;
                }
            }

            let node_idx = current.id as usize;

            // Explore neighbors
            for &neighbor_idx in &nodes[node_idx].neighbors {
                if visited.insert(neighbor_idx) {
                    let dist = l2_distance(query, &nodes[neighbor_idx].vector);

                    if results.len() < ef {
                        results.push(SearchCandidate { id: neighbor_idx as u64, distance: -dist });
                        candidates.push(SearchCandidate { id: neighbor_idx as u64, distance: dist });
                    } else if let Some(&worst) = results.peek() {
                        if dist < -worst.distance {
                            results.pop();
                            results.push(SearchCandidate { id: neighbor_idx as u64, distance: -dist });
                            candidates.push(SearchCandidate { id: neighbor_idx as u64, distance: dist });
                        }
                    }
                }
            }
        }

        // Convert results to vec with correct distances
        results.into_iter()
            .map(|c| SearchCandidate { id: c.id, distance: -c.distance })
            .collect()
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let nodes = self.nodes.read().unwrap();

        if nodes.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;
        let ef = (EF_SEARCH.max(top_k)) as usize;

        // Search NSW graph to get candidates
        let candidates = self.search_nsw(query, ef, &nodes);

        // Extract top-k from candidates
        let mut results: Vec<SearchCandidate> = candidates.into_iter()
            .take(top_k)
            .collect();

        // Sort by distance ascending
        results.sort_by(|a, b| {
            a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal)
        });

        results
            .into_iter()
            .map(|c| SearchResult {
                id: nodes[c.id as usize].id,
                distance: c.distance,
            })
            .collect()
    }
}

