const DIM: usize = 128;
const NUM_CLUSTERS: usize = 100; // Number of IVF clusters
const NPROBE: usize = 5; // Number of clusters to search

#[derive(Clone, Copy)]
struct SearchCandidate {
    id: u64,
    distance: f64,
}

impl PartialEq for SearchCandidate {
    fn eq(&self, other: &Self) -> bool {
