struct Cluster {
    centroid: Vec<f32>,
    ids: Vec<u64>,
    vectors: Vec<f32>, // Flattened vectors
}

pub struct VectorDB {
    clusters: RwLock<Vec<Cluster>>,
    is_trained: RwLock<bool>,
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            clusters: RwLock::new(Vec::new()),
            is_trained: RwLock::new(false),
        }
    }

    // Simple k-means++ initialization for centroids
    fn kmeans_plus_plus(vectors: &[(u64, Vec<f32>)], k: usize) -> Vec<Vec<f32>> {
        let mut rng = thread_rng();
        let mut centroids = Vec::with_capacity(k);

        // Choose first centroid randomly
        if !vectors.is_empty() {
            centroids.push(vectors[0].1.clone());
        }

        // Choose remaining centroids
        for _ in 1..k.min(vectors.len()) {
            // Find distances to closest centroid
            let distances: Vec<f64> = vectors.iter()
                .map(|(_, vec)| {
                    centroids.iter()
                        .map(|c| l2_distance(vec, c))
                        .fold(f64::INFINITY, |a, b| a.min(b))
                })
                .collect();

            // Sample with probability proportional to squared distance
            let total: f64 = distances.iter().sum();
            let threshold = rng.gen::<f64>() * total;
            let mut cumsum = 0.0;
            let mut chosen = 0;

            for (i, &d) in distances.iter().enumerate() {
                cumsum += d;
                if cumsum >= threshold {
                    chosen = i;
                    break;
                }
            }

            centroids.push(vectors[chosen].1.clone());
        }

        centroids
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut clusters = self.clusters.write().unwrap();
        let is_trained = self.is_trained.read().unwrap();

        if *is_trained {
            // Find closest cluster and add there
            let closest = clusters.iter()
                .enumerate()
                .map(|(i, c)| (i, l2_distance(&vector, &c.centroid)))
                .min_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal))
                .map(|(i, _)| i)
                .unwrap_or(0);

            clusters[closest].ids.push(id);
            clusters[closest].vectors.extend_from_slice(&vector);
        } else {
            // Simple single cluster fallback
            if clusters.is_empty() {
                clusters.push(Cluster {
                    centroid: vec![0.0; DIM],
                    ids: Vec::new(),
                    vectors: Vec::new(),
                });
            }
            clusters[0].ids.push(id);
            clusters[0].vectors.extend_from_slice(&vector);
        }
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = vectors.len();

        if count < NUM_CLUSTERS * 10 {
            // Too few vectors for clustering, use flat storage
            let mut clusters = self.clusters.write().unwrap();
            if clusters.is_empty() {
                clusters.push(Cluster {
                    centroid: vec![0.0; DIM],
                    ids: Vec::new(),
                    vectors: Vec::new(),
                });
            }
            for (id, vec) in vectors {
                clusters[0].ids.push(id);
                clusters[0].vectors.extend_from_slice(&vec);
            }
            return count;
        }

        // Initialize centroids using k-means++
        let centroids = Self::kmeans_plus_plus(&vectors, NUM_CLUSTERS);

        // Initialize clusters
        let mut clusters: Vec<Cluster> = centroids.into_iter()
            .map(|c| Cluster {
                centroid: c,
                ids: Vec::new(),
                vectors: Vec::new(),
            })
            .collect();

        // Assign vectors to clusters
        for (id, vec) in vectors {
            let closest = clusters.iter()
                .enumerate()
                .map(|(i, c)| (i, l2_distance(&vec, &c.centroid)))
                .min_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal))
                .map(|(i, _)| i)
                .unwrap_or(0);

            clusters[closest].ids.push(id);
            clusters[closest].vectors.extend_from_slice(&vec);
        }

        // Update centroids (average of assigned vectors)
        for cluster in &mut clusters {
            if !cluster.ids.is_empty() {
                let n = cluster.ids.len();
                for d in 0..DIM {
                    let mut sum = 0.0f64;
                    for i in 0..n {
                        sum += cluster.vectors[i * DIM + d] as f64;
                    }
                    cluster.centroid[d] = (sum / n as f64) as f32;
                }
            }
        }

        let mut guard = self.clusters.write().unwrap();
        *guard = clusters;
        *self.is_trained.write().unwrap() = true;

        count
    }

    fn search_cluster(query: &[f32], cluster: &Cluster, top_k: usize) -> Vec<SearchCandidate> {
        let num_vectors = cluster.ids.len();
        let mut heap = BinaryHeap::with_capacity(top_k);

        for idx in 0..num_vectors {
            let start = idx * DIM;
            let vec = &cluster.vectors[start..start + DIM];
            let dist = l2_distance(query, vec);
            let candidate = SearchCandidate {
                id: idx as u64,
                distance: dist,
            };

            if heap.len() < top_k {
                heap.push(candidate);
            } else if let Some(&max) = heap.peek() {
                if candidate.distance < max.distance {
                    heap.pop();
                    heap.push(candidate);
                }
            }
        }

        heap.into_sorted_vec()
    }

    pub fn search(&self, query: &[f32], top_k: u32) -> Vec<SearchResult> {
        let clusters = self.clusters.read().unwrap();
        let is_trained = self.is_trained.read().unwrap();

        if clusters.is_empty() {
            return Vec::new();
        }

        let top_k = top_k as usize;

        if !*is_trained || clusters.len() == 1 {
            // Flat search
            let cluster = &clusters[0];
            let results = Self::search_cluster(query, cluster, top_k);

            results.into_iter()
                .map(|c| SearchResult {
                    id: cluster.ids[c.id as usize],
                    distance: c.distance,
                })
                .collect()
        } else {
            // IVF search: find closest clusters
            let mut cluster_distances: Vec<(usize, f64)> = clusters.iter()
                .enumerate()
                .map(|(i, c)| (i, l2_distance(query, &c.centroid)))
                .collect();

            cluster_distances.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal));

            // Search top NPROBE clusters
            let probe_count = NPROBE.min(clusters.len());
            let mut all_results: Vec<SearchCandidate> = Vec::new();

            for &(cluster_idx, _) in cluster_distances.iter().take(probe_count) {
                let cluster = &clusters[cluster_idx];
                let cluster_results = Self::search_cluster(query, cluster, top_k);

                for cand in cluster_results {
                    all_results.push(SearchCandidate {
                        id: cluster.ids[cand.id as usize],
                        distance: cand.distance,
                    });
                }
            }

            // Find global top-k
            all_results.select_nth_unstable_by(top_k.min(all_results.len().saturating_sub(1)), |a, b| {
                a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal)
            });

            let mut results: Vec<SearchCandidate> = all_results.into_iter().take(top_k).collect();
            results.sort_by(|a, b| {
                a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal)
            });

            results.into_iter()
                .map(|c| SearchResult {
                    id: c.id,
                    distance: c.distance,
                })
                .collect()
        }
    }
}

